[CmdletBinding()]param([Parameter(Mandatory)][string]$SignToolPath,[Parameter(Mandatory)][string]$CertificateThumbprint,[Parameter(Mandatory)][uri]$TimestampUrl,[Parameter(Mandatory)][string]$InputPath)
$ErrorActionPreference='Stop';if(-not(Test-Path $SignToolPath -PathType Leaf)){throw 'SignTool missing.'};$cert=Get-ChildItem Cert:\CurrentUser\My,Cert:\LocalMachine\My|Where-Object Thumbprint -eq $CertificateThumbprint|Select -First 1;if(-not$cert){throw 'Certificate not found.'};if($cert.NotAfter-le(Get-Date)){throw 'Certificate expired.'};if(-not($cert.EnhancedKeyUsageList.ObjectId.Value-contains'1.3.6.1.5.5.7.3.3')){throw 'Code Signing EKU missing.'};& $SignToolPath sign /sha1 $CertificateThumbprint /fd SHA256 /tr $TimestampUrl.AbsoluteUri /td SHA256 $InputPath;if($LASTEXITCODE){throw 'Signing failed.'};& $SignToolPath verify /pa /tw /v $InputPath;if($LASTEXITCODE){throw 'Signature verification failed.'};Write-Host "Signed by $($cert.Subject); thumbprint=...$($cert.Thumbprint.Substring($cert.Thumbprint.Length-8)); SHA256=$((Get-FileHash $InputPath -Algorithm SHA256).Hash)"
